	@Override
	public Object visit(ASTBind node, Object data) throws VisitorException {
		// bind expression
		Object child0 = node.jjtGetChild(0).jjtAccept(this, data);
		ValueExpr ve;
		if (child0 instanceof ValueExpr) {
			ve = castToValueExpr(child0);
		} else if (child0 instanceof TripleRef) {
			TripleRef tripleRef = (TripleRef) child0;

			// Check if all triple term variables are bound in preceding patterns
			Set<Var> boundVars = collectBoundVars(graphPattern.getRequiredTEs());
			Set<Var> tripleTermVars = getTripleRefVars(tripleRef);

			if (!tripleTermVars.isEmpty() && boundVars.containsAll(tripleTermVars)) {
				// All vars bound - expand to ValueExprTripleRef
				ve = castToValueExpr(child0);
			} else {
				// Some vars unbound - use simple var reference
				graphPattern.addRequiredTE(tripleRef);
				ve = ((TripleRef) child0).getExprVar();
			}
		} else {
			ve = null;
		}
		if (ve == null) {
			throw new IllegalArgumentException("Unexpected expression on bind");
		}

		// name to bind the expression outcome to
		Node aliasNode = node.jjtGetChild(1);
		String alias = ((ASTVar) aliasNode).getName();
		verifyLateralAssignment(alias, "BIND clause alias");

		Extension extension = new Extension();
		extension.addElement(new ExtensionElem(ve.clone(), alias));

		TupleExpr result;

		// get a tupleExpr that represents the basic graph pattern, sofar.
		TupleExpr arg = graphPattern.buildJoinFromRequiredTEs();
		// apply optionals, if any
		arg = graphPattern.buildOptionalTE(arg);

		// check if alias is not previously used in the BGP
		if (arg.getBindingNames().contains(alias)) {
			// SES-2314 we need to double-check that the reused varname is not just
			// for an anonymous var or a constant.
			VarCollector collector = new VarCollector();
			arg.visit(collector);
			for (Var v : collector.getCollectedVars()) {
				if (alias.equals(v.getName())) {
					if (!v.isConstant() && !v.isAnonymous()) {
						throw new VisitorException(String.format("BIND clause alias '%s' was previously used", alias));
					}
					break;
				}
			}
		}

		extension.setArg(arg);
		result = extension;

		// replace the previous basic graph pattern with the extended version
		graphPattern.clearRequiredTEs();
		graphPattern.addRequiredTE(result);

		return result;
	}

