	@Override
	public ValueConstant visit(ASTRDFLiteral node, Object data) throws VisitorException {
		String label = (String) node.getLabel().jjtAccept(this, null);
		String lang = node.getLang();
		ASTIRI datatypeNode = node.getDatatype();

		Literal literal;
		if (datatypeNode != null) {
			IRI datatype;
			try {
				datatype = valueFactory.createIRI(datatypeNode.getValue());
			} catch (IllegalArgumentException e) {
				// invalid URI
				throw new VisitorException(e.getMessage());
			}
			literal = valueFactory.createLiteral(label, datatype);
		} else if (lang != null) {
			int sep = lang.indexOf(Literal.BASE_DIR_SEPARATOR);
			if (sep >= 0) {
				String langOnly = lang.substring(0, sep);
				String dirSuffix = lang.substring(sep);
				Literal.BaseDirection dir = Literal.BaseDirection.fromString(dirSuffix);
				literal = valueFactory.createLiteral(label, langOnly, dir);
			} else {
				literal = valueFactory.createLiteral(label, lang);
			}
		} else {
			literal = valueFactory.createLiteral(label, CoreDatatype.XSD.STRING);
		}

		return new ValueConstant(literal);
	}

